uint256 lastRecordedBalance;

    function onDeposit() public {
        require(msg.sender == market, "ONLY MARKET");
        uint256 invBalance = token.balanceOf(address(this));
        if (invBalance - lastRecordedBalance> 0) {
            xINV.mint(invBalance- lastRecordedBalance); // we do not check return value because we don't want errors to block this call
            lastRecordedBalance = invBalance;
        }

    function pay(address recipient, uint256 amount) public {
        require(msg.sender == market, "ONLY MARKET");
        uint256 invBalance = token.balanceOf(address(this));
        if (invBalance < amount) xINV.redeemUnderlying(amount - invBalance); // we do not check return value because next call will fail if this fails anyway
        token.transfer(recipient, amount);

       }
       lastRecordedBalance = invBalance - amount;
    }
